int judge(IMAGE_T &image) {
    int best_label = -1;
    double min_dist = std::numeric_limits<double>::max();

    for (int l = 0; l < 10; ++l) {
        double dist = 0;
        for (int i = 0; i < 28; ++i) {
            for (int j = 0; j < 28; ++j) {
                double diff = image[i][j] - templates[l][i][j];
                dist += diff * diff;
            }
        }
        if (dist < min_dist) {
            min_dist = dist;
            best_label = l;
        }
    }

    return best_label;
}
